create table dirkspzm32.isi_res_personal_bedarf (
    sid                         varchar2(2 char) not null enable,
    firma_nr                    number(6, 0) not null enable,
    res_id                      number(*, 0) not null enable,
    created_date                date not null enable,
    created_login_id            number(*, 0) default - 1,
    last_change_date            date,
    last_change_login_id        number(*, 0),
    res_personal_bedarf_grp     varchar2(50 char) default '1' not null enable,
    vorgangsqualifikation       varchar2(50 char) not null enable,
    vorgangstyp                 number(*, 0) default 1 not null enable,
    res_personal_wechsel        number(*, 0) default 0 not null enable,
    res_personal_bedarf_anz     number(*, 0) default 1 not null enable,
    res_personal_bedarf_anz_max number(*, 0) default 0 not null enable,
    res_personal_proz_ausl      number(*, 6) default 100 not null enable
);

alter table dirkspzm32.isi_res_personal_bedarf
    add constraint pk_isi_res_personal_bedarf
        primary key ( res_id,
                      vorgangsqualifikation,
                      firma_nr,
                      sid )
            using index enable;


